function InfoModal({ item, onClose }) {
  const content = INFO_CONTENT[item];
  if (!content) return null;
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.75)", zIndex: 500, display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#0f1117", border: "1px solid #1e2030", borderRadius: 20, maxWidth: 680, width: "100%", maxHeight: "82vh", display: "flex", flexDirection: "column", boxShadow: "0 32px 80px rgba(0,0,0,0.7)" }}>
        <div style={{ padding: "24px 28px 20px", borderBottom: "1px solid #1e2030", display: "flex", justifyContent: "space-between", alignItems: "center", flexShrink: 0 }}>
          <h2 style={{ fontWeight: 800, fontSize: 20, color: "#fbbf24" }}>{content.title}</h2>
          <button onClick={onClose} style={{ background: "#111218", border: "1px solid #1e2030", color: "#9ca3af", borderRadius: 8, width: 34, height: 34, fontSize: 18, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", flexShrink: 0 }}>✕</button>
        </div>
        <div style={{ padding: "24px 28px", overflowY: "auto", flex: 1 }}>
          {content.body.split("\n\n").map((para, i) => {
            // Render clickable links for Telegram and email lines
            if (para.includes("t.me/BitGrowOfficial")) {
              return (
                <p key={i} style={{ fontSize: 14, lineHeight: 1.85, marginBottom: 16, whiteSpace: "pre-line" }}>
                  {para.split("👉 t.me/BitGrowOfficial").map((part, j) => j === 0 ? (
                    <span key={j} style={{ color: "#9ca3af" }}>{part}</span>
                  ) : (
                    <span key={j}>
                      <a href="https://t.me/BitGrowOfficial" target="_blank" rel="noreferrer"
                        style={{ color: "#fbbf24", fontWeight: 700, textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6 }}>
                        👉 t.me/BitGrowOfficial ↗
                      </a>
                      <span style={{ color: "#9ca3af" }}>{part}</span>
                    </span>
                  ))}
                </p>
              );
            }
            if (para.includes("bitgrowofficial1@gmail.com")) {
              return (
                <p key={i} style={{ fontSize: 14, lineHeight: 1.85, marginBottom: 16, whiteSpace: "pre-line" }}>
                  {para.split("👉 bitgrowofficial1@gmail.com").map((part, j) => j === 0 ? (
                    <span key={j} style={{ color: "#9ca3af" }}>{part}</span>
                  ) : (
                    <span key={j}>
                      <a href="mailto:bitgrowofficial1@gmail.com"
                        style={{ color: "#fbbf24", fontWeight: 700, textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6 }}>
                        👉 bitgrowofficial1@gmail.com ↗
                      </a>
                      <span style={{ color: "#9ca3af" }}>{part}</span>
                    </span>
                  ))}
                </p>
              );
            }
            return (
              <p key={i} style={{ color: para.startsWith("Q:") || para.startsWith("•") ? "#e8eaf0" : para.match(/^[0-9]+\./) ? "#fbbf24" : para.match(/^(📱|📧|💬)/) ? "#e8eaf0" : "#9ca3af", fontSize: 14, lineHeight: 1.85, marginBottom: 16, fontWeight: para.match(/^[0-9]+\./) || para.match(/^(📱|📧|💬)/) ? 700 : 400, whiteSpace: "pre-line" }}>{para}</p>
            );
          })}
        </div>
        <div style={{ padding: "16px 28px", borderTop: "1px solid #1e2030", flexShrink: 0 }}>
          <button onClick={onClose} style={{ background: "linear-gradient(135deg,#fbbf24,#f97316)", color: "#07080f", border: "none", padding: "10px 28px", borderRadius: 10, fontWeight: 700, fontSize: 14 }}>Close</button>
        </div>
      </div>
    </div>
  );
}

